import anthropic, json, base64, pathlib

def read_text_file(path: str) -> str:
    try:
        return pathlib.Path(path).read_text()[:4000]
    except Exception as e:
        return f"Error reading file: {e}"

def run_python(code: str) -> str:
    import subprocess, sys
    result = subprocess.run(
        [sys.executable, "-c", code],
        capture_output=True, text=True, timeout=10
    )
    return (result.stdout + result.stderr)[:2000]

def eval_expression(expression: str) -> str:
    try:
        return str(eval(expression, {"__builtins__": {"abs": abs, "round": round, "int": int, "float": float}}))
    except Exception as e:
        return f"Error: {e}"

TOOLS = [
    {
        "name": "search_web",
        "description": "Search the web for factual information. Returns a short summary.",
        "input_schema": {"type": "object",
                         "properties": {"query": {"type": "string"}},
                         "required": ["query"]},
    },
    {
        "name": "read_file",
        "description": "Read text content from an attached file (txt, csv, md, py).",
        "input_schema": {"type": "object",
                         "properties": {"path": {"type": "string"}},
                         "required": ["path"]},
    },
    {
        "name": "run_python",
        "description": "Execute Python code and return stdout. Use for arithmetic, data processing.",
        "input_schema": {"type": "object",
                         "properties": {"code": {"type": "string"}},
                         "required": ["code"]},
    },
    {
        "name": "calculator",
        "description": "Evaluate a simple numeric expression: '(5 * 12) + 7'.",
        "input_schema": {"type": "object",
                         "properties": {"expression": {"type": "string"}},
                         "required": ["expression"]},
    },
]

SYSTEM = """
You are an expert research assistant.
Your goal is to answer the user's question with a SHORT, EXACT answer.
Use tools to look up information, compute values, and read files.
When you have the final answer, output ONLY the answer string — no explanation,
no leading text, no units unless the question asks for them.
"""

def gaia_agent(question: str, file_path: str | None = None) -> str:
    client = anthropic.Anthropic()
    context = f"Question: {question}"
    if file_path:
        context += f"\nAttached file: {file_path}"
    messages = [{"role": "user", "content": context}]

    def fake_search(query: str) -> str:
        return f"[Search result for '{query}']: This is a simulated result."

    for _ in range(15):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=SYSTEM,
            tools=TOOLS,
            messages=messages,
        )

        if resp.stop_reason == "end_turn":
            return " ".join(b.text for b in resp.content if hasattr(b, "text")).strip()

        if resp.stop_reason == "tool_use":
            tool_results = []
            for block in resp.content:
                if block.type == "tool_use":
                    name, args = block.name, block.input
                    if name == "search_web":
                        result = fake_search(args["query"])
                    elif name == "read_file":
                        result = read_text_file(args["path"])
                    elif name == "run_python":
                        result = run_python(args["code"])
                    elif name == "calculator":
                        result = eval_expression(args["expression"])
                    else:
                        result = f"Unknown tool: {name}"
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages += [
                {"role": "assistant", "content": resp.content},
                {"role": "user", "content": tool_results},
            ]

    return ""   # failed to answer within step budget

answer = gaia_agent("What is 17 times 23?")
print(f"Answer: '{answer}'")
