import pathlib, mimetypes, subprocess, sys

def detect_file_type(path: str) -> str:
    """Return a simplified category for the file."""
    mime, _ = mimetypes.guess_type(path)
    if not mime:
        # Fallback: read first bytes to check for binary magic numbers
        try:
            header = pathlib.Path(path).read_bytes()[:8]
            if header.startswith(b'%PDF'):
                return "pdf"
            if header[:4] in (b'PK\x03\x04', b'PK\x05\x06'):
                return "excel"   # XLSX is a ZIP
        except Exception:
            pass
        return "text"
    if "pdf" in mime:
        return "pdf"
    if "image" in mime:
        return "image"
    if "audio" in mime:
        return "audio"
    if "spreadsheet" in mime or "excel" in mime or "csv" in mime:
        return "spreadsheet"
    return "text"

def extract_text_from_pdf(path: str) -> str:
    """Extract text from a PDF using pdfminer.six (pip install pdfminer.six)."""
    try:
        from pdfminer.high_level import extract_text
        return extract_text(path)[:5000]
    except ImportError:
        return "[pdfminer.six not installed — cannot read PDF]"
    except Exception as e:
        return f"PDF extraction error: {e}"

def read_csv(path: str) -> str:
    """Read a CSV and return its content as a markdown table."""
    import csv
    try:
        rows = list(csv.reader(open(path)))
        if not rows:
            return "(empty CSV)"
        header = " | ".join(rows[0])
        sep    = " | ".join(["---"] * len(rows[0]))
        body   = "\n".join(" | ".join(r) for r in rows[1:10])  # first 10 data rows
        return f"{header}\n{sep}\n{body}"
    except Exception as e:
        return f"CSV read error: {e}"

def process_attached_file(path: str) -> str:
    """Return text content suitable for passing to an LLM."""
    file_type = detect_file_type(path)
    if file_type == "pdf":
        return extract_text_from_pdf(path)
    elif file_type == "spreadsheet":
        return read_csv(path)
    elif file_type == "image":
        return f"[Image file at {path} — use a vision model to describe it]"
    elif file_type == "audio":
        return f"[Audio file at {path} — use a speech-to-text tool to transcribe it]"
    else:
        try:
            return pathlib.Path(path).read_text()[:4000]
        except Exception as e:
            return f"Read error: {e}"

